(async function() {
  const host = document.querySelector('floorplan-navigator');
  if (!host || !host.shadowRoot) return;
  const sr = host.shadowRoot;
  const floors = sr.querySelectorAll('li.unit-filters__floor');
  if (!floors.length) return;
  const allLines = ['=== SIGNAL PER-UNIT LISTINGS (RentSync FPN shadow DOM) ==='];
  let totalUnits = 0;
  for (let i = 0; i < floors.length; i++) {
    floors[i].dispatchEvent(new MouseEvent('click', {bubbles: true, cancelable: true}));
    await new Promise(r => setTimeout(r, 1200));
    const cards = sr.querySelectorAll('.unit-listing__item');
    const floorLabel = (floors[i].textContent || '').trim().replace(/\s+/g, ' ');
    const floorLines = ['', 'FLOOR: ' + floorLabel + ' (' + cards.length + ' suites)'];
    const seen = new Set();
    for (const c of cards) {
      const inner = c.querySelector('.unit-card') || c;
      const id = inner.getAttribute('data-unit-id') || (inner.outerHTML.length + ':' + inner.textContent.slice(0, 30));
      if (seen.has(id)) continue;
      seen.add(id);
      const num = (c.querySelector('.unit-card__title--number') ? c.querySelector('.unit-card__title--number').textContent.trim() : '').replace(/\s+/g, ' ');
      const bed = (c.querySelector('.unit-card__bed') ? c.querySelector('.unit-card__bed').textContent.trim() : '').replace(/\s+/g, ' ');
      const bath = (c.querySelector('.unit-card__bath') ? c.querySelector('.unit-card__bath').textContent.trim() : '').replace(/\s+/g, ' ');
      const sqft = (c.querySelector('.unit-card__sqFt') ? c.querySelector('.unit-card__sqFt').textContent.trim() : '').replace(/\s+/g, ' ');
      floorLines.push('  ' + num + ' | ' + bed + ' | ' + bath + ' | ' + sqft);
      totalUnits++;
    }
    if (floorLines.length > 2) allLines.push(...floorLines);
  }
  allLines.push('');
  allLines.push('TOTAL UNITS EXTRACTED FROM FPN: ' + totalUnits);
  const pre = document.createElement('pre');
  pre.id = 'signal-units-dump';
  pre.style.cssText = 'display:block;white-space:pre-wrap;font-family:monospace;padding:20px;z-index:1;position:relative;';
  pre.textContent = allLines.join('\n');
  document.body.appendChild(pre);
})();

(async () => {
  // Click Load More until gone
  for (let i = 0; i < 20; i++) {
    const btns = document.querySelectorAll('button.uk3-button-default');
    let clicked = false;
    for (const btn of btns) {
      if (btn.textContent.toLowerCase().includes('load')) {
        btn.click();
        clicked = true;
        break;
      }
    }
    if (!clicked) break;
    await new Promise(r => setTimeout(r, 2000));
  }
  await new Promise(r => setTimeout(r, 2000));

  // Read all unit-group-card textContent (hidden from innerText)
  const cards = document.querySelectorAll('.unit-group-card');
  const modals = document.querySelectorAll('.unit-group-modal');
  let text = '[UNIT LISTINGS]\n';
  for (const card of cards) {
    const t = card.textContent.trim();
    if (t) text += t + '\n---\n';
  }
  for (const modal of modals) {
    const t = modal.textContent.trim();
    if (t.length > 50) text += '[MODAL]\n' + t + '\n---\n';
  }
  text += '[/UNIT LISTINGS]\n';

  // Inject as visible div so innerText capture picks it up
  const div = document.createElement('div');
  div.id = 'scraper-injected';
  div.textContent = text;
  document.body.prepend(div);
})()

(function(){
  const blocks = document.querySelectorAll('.popup-info-in');
  const lines = ['', '=== ARCHETYPE AVAILABLE UNIT LISTINGS ==='];
  for (const p of blocks) {
    const h = p.querySelector('h3, h2');
    const planName = h ? h.textContent.trim().replace(/\s+/g, ' ') : '';
    const beds = (p.querySelector('.bedrooms') ? p.querySelector('.bedrooms').textContent.trim().replace(/\s+/g, ' ') : '');
    const baths = (p.querySelector('.bathrooms') ? p.querySelector('.bathrooms').textContent.trim().replace(/\s+/g, ' ') : '');
    const sqft = (p.querySelector('.sq-ft-range') ? p.querySelector('.sq-ft-range').textContent.trim().replace(/\s+/g, ' ') : '');
    const price = (p.querySelector('.price-range') ? p.querySelector('.price-range').textContent.trim().replace(/\s+/g, ' ') : '');
    const rows = p.querySelectorAll('table tr');
    const unitRows = [];
    for (const r of rows) {
      const cells = Array.from(r.querySelectorAll('td')).map(c => c.textContent.trim().replace(/\s+/g, ' '));
      if (cells.length >= 3 && cells[0].startsWith('#')) {
        unitRows.push(cells);
      }
    }
    lines.push('');
    lines.push('PLAN: ' + planName + ' | ' + beds + ' | ' + baths + ' | ' + sqft + ' | card price: ' + price);
    lines.push('Available units for this plan: ' + unitRows.length);
    for (const u of unitRows) {
      lines.push('  Unit ' + u[0] + ' - sqft ' + u[1] + ' - rent ' + u[2]);
    }
  }
  const pre = document.createElement('pre');
  pre.id = 'archetype-units-dump';
  pre.style.cssText = 'position:relative;z-index:1;display:block;white-space:pre-wrap;font-family:monospace;padding:20px;';
  pre.textContent = lines.join('\n');
  document.body.appendChild(pre);
})();
